{
  "title": "कमांड प्रतिस्थापन",
  "group": "ध्यान देने योग्य बातें",
  "options": [
    {
      "text": "'ls -l'"
    },
    {
      "text": "% ls -l"
    },
    {
      "text": "$ ls -l"
    },
    {
      "text": "$(ls -l)"
    },
    {
      "text": "${ls -l}"
    }
  ],
  "questionProse": [
    "कौन सा विकल्प `ls -l` कमांड को चलाएगा और आउटपुट लौटाएगा?"
  ],
  "explanationProse": [
    "`$(ls -l)` सिंटैक्स कमांड को **कोष्ठकों** के भीतर चलाता है और आउटपुट को प्रतिस्थापित करता है। उदाहरण के लिए:",
    "पहला विकल्प सिंगल कोट्स `'` का उपयोग करता है, **बैकटिक्स नहीं**। यह विस्तार को रोकता है, इसलिए `'$(date +%F)'` केवल स्ट्रिंग `$(date +%F)` को ही प्रिंट करेगा।\n\n    जबकि कमांड निष्पादन के लिए बैकटिक्स (`` `ls -l` ``) अभी भी समर्थित हैं, हाल ही में यह कुछ संदर्भों में एक एंटी‑पैटर्न बन गया है। अधिकांश लोग बेहतर पठनीयता और विभिन्न शेल व संस्करणों में संगतता के लिए `$(command)` का उपयोग करने की सलाह देते हैं।\n\n    कर्ली ब्रेसेस `${}` वेरिएबल विस्तार के लिए उपयोग होते हैं, कमांड प्रतिस्थापन के लिए नहीं।\n\n    `%` अक्षर कमांड प्रतिस्थापन के लिए उपयोग नहीं होता।"
  ]
}
